fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let level_in = required_f32(params, "level_in").map_err(anyhow::Error::msg)?;
    let level_out = required_f32(params, "level_out").map_err(anyhow::Error::msg)?;
    let ls_active = required_f32(params, "ls_active").map_err(anyhow::Error::msg)?;
    let ls_level = required_f32(params, "ls_level").map_err(anyhow::Error::msg)?;
    let ls_freq = required_f32(params, "ls_freq").map_err(anyhow::Error::msg)?;
    let hs_active = required_f32(params, "hs_active").map_err(anyhow::Error::msg)?;
    let hs_level = required_f32(params, "hs_level").map_err(anyhow::Error::msg)?;
    let hs_freq = required_f32(params, "hs_freq").map_err(anyhow::Error::msg)?;
    let p1_active = required_f32(params, "p1_active").map_err(anyhow::Error::msg)?;
    let p1_level = required_f32(params, "p1_level").map_err(anyhow::Error::msg)?;
    let p1_freq = required_f32(params, "p1_freq").map_err(anyhow::Error::msg)?;
    let p1_q = required_f32(params, "p1_q").map_err(anyhow::Error::msg)?;
    let p2_active = required_f32(params, "p2_active").map_err(anyhow::Error::msg)?;
    let p2_level = required_f32(params, "p2_level").map_err(anyhow::Error::msg)?;
    let p2_freq = required_f32(params, "p2_freq").map_err(anyhow::Error::msg)?;
    let p2_q = required_f32(params, "p2_q").map_err(anyhow::Error::msg)?;
    let p3_active = required_f32(params, "p3_active").map_err(anyhow::Error::msg)?;
    let p3_level = required_f32(params, "p3_level").map_err(anyhow::Error::msg)?;
    let p3_freq = required_f32(params, "p3_freq").map_err(anyhow::Error::msg)?;
    let p3_q = required_f32(params, "p3_q").map_err(anyhow::Error::msg)?;
    let individuals = required_bool(params, "individuals").map_err(anyhow::Error::msg)?;
    let zoom = required_f32(params, "zoom").map_err(anyhow::Error::msg)?;
    let analyzer = required_bool(params, "analyzer").map_err(anyhow::Error::msg)?;
    let analyzer_mode = required_f32(params, "analyzer_mode").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_LEVEL_IN, level_in),
        (PORT_CTRL_LEVEL_OUT, level_out),
        (PORT_CTRL_LS_ACTIVE, ls_active),
        (PORT_CTRL_LS_LEVEL, ls_level),
        (PORT_CTRL_LS_FREQ, ls_freq),
        (PORT_CTRL_HS_ACTIVE, hs_active),
        (PORT_CTRL_HS_LEVEL, hs_level),
        (PORT_CTRL_HS_FREQ, hs_freq),
        (PORT_CTRL_P1_ACTIVE, p1_active),
        (PORT_CTRL_P1_LEVEL, p1_level),
        (PORT_CTRL_P1_FREQ, p1_freq),
        (PORT_CTRL_P1_Q, p1_q),
        (PORT_CTRL_P2_ACTIVE, p2_active),
        (PORT_CTRL_P2_LEVEL, p2_level),
        (PORT_CTRL_P2_FREQ, p2_freq),
        (PORT_CTRL_P2_Q, p2_q),
        (PORT_CTRL_P3_ACTIVE, p3_active),
        (PORT_CTRL_P3_LEVEL, p3_level),
        (PORT_CTRL_P3_FREQ, p3_freq),
        (PORT_CTRL_P3_Q, p3_q),
        (PORT_CTRL_INDIVIDUALS, if individuals { 1.0 } else { 0.0 }),
        (PORT_CTRL_ZOOM, zoom),
        (PORT_CTRL_ANALYZER, if analyzer { 1.0 } else { 0.0 }),
        (PORT_CTRL_ANALYZER_MODE, analyzer_mode),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

